import{_ as e,o as a,c as i,a2 as t}from"./chunks/framework.DZO5kRrk.js";const k=JSON.parse('{"title":"前端转 Flutter 笔记 (Day 28)：性能调优 (DevTools) 🏎️","description":"","frontmatter":{},"headers":[],"relativePath":"docs/flutter/day-28-performance.md","filePath":"docs/flutter/day-28-performance.md"}'),n={name:"docs/flutter/day-28-performance.md"};function o(l,s,r,p,d,h){return a(),i("div",null,[...s[0]||(s[0]=[t(`<h1 id="前端转-flutter-笔记-day-28-性能调优-devtools-🏎️" tabindex="-1">前端转 Flutter 笔记 (Day 28)：性能调优 (DevTools) 🏎️ <a class="header-anchor" href="#前端转-flutter-笔记-day-28-性能调优-devtools-🏎️" aria-label="Permalink to &quot;前端转 Flutter 笔记 (Day 28)：性能调优 (DevTools) 🏎️&quot;">​</a></h1><blockquote><p><strong>前言</strong>： &quot;为什么我的 Flutter App 跑起来这么卡？掉帧严重？甚至手机发烫？&quot; 很多初学者甚至进阶开发者都会遇到性能瓶颈。相比于 Web 前端的 <code>Chrome DevTools</code> (Lighthouse, Performance tab)，Flutter 官方其实也提供了一套极其强大的武器库：<strong>Flutter DevTools</strong>。</p><p>这一章节，我们将深入诊断与优化，从帧率断崖下跌的元凶入手，让你的应用丝滑如德芙。</p></blockquote><hr><h2 id="_1-终极武器-flutter-devtools" tabindex="-1">1. 终极武器：Flutter DevTools <a class="header-anchor" href="#_1-终极武器-flutter-devtools" aria-label="Permalink to &quot;1. 终极武器：Flutter DevTools&quot;">​</a></h2><p>Flutter DevTools 是一套独立于 IDE 运行在浏览器中的性能分析工具。只要你的应用在 Debug 或 Profile 模式下运行，你就可以启动它。</p><p><strong>启动方式</strong>：</p><ul><li>VS Code: 命令面板 (Cmd+Shift+P) 输入 <code>Flutter: Open DevTools</code></li><li>终端: <code>flutter pub global activate devtools</code>，然后 <code>devtools</code></li></ul><h3 id="_1-1-performance-性能面板" tabindex="-1">1.1 Performance (性能面板) <a class="header-anchor" href="#_1-1-performance-性能面板" aria-label="Permalink to &quot;1.1 Performance (性能面板)&quot;">​</a></h3><p>这是你最常去的图表页。关注图表中的条形图（帧渲染时间）。</p><ul><li><strong>绿色</strong>：低于 16ms (如果你是 60Hz 屏幕)，恭喜，如丝般顺滑。</li><li><strong>红色</strong>：超过 16ms (Jank)，这就是卡顿的根源。</li></ul><p><strong>注意点</strong>：永远不要在 Debug 模式下测试性能！Debug 模式带有大量的热重载钩子和未优化的断言。<strong>一定要使用 Profile 模式 (<code>flutter run --profile</code>) 来进行性能调优分析。</strong></p><h3 id="_1-2-memory-内存面板" tabindex="-1">1.2 Memory (内存面板) <a class="header-anchor" href="#_1-2-memory-内存面板" aria-label="Permalink to &quot;1.2 Memory (内存面板)&quot;">​</a></h3><p>用于排查内存泄漏。就像前端 SPA 的闭包泄漏一样，在 Flutter 中，未被 <code>dispose</code> 的 <code>StreamSubscription</code>、<code>ScrollController</code>、以及过大的图片加载都会导致 OOM (Out Of Memory)。</p><p>通过点击 <code>Snapshot</code> 抓取不同时刻的内存快照，找出一直在增长却没被回收的实例。</p><hr><h2 id="_2-常见卡顿原因及处方药-💊" tabindex="-1">2. 常见卡顿原因及处方药 💊 <a class="header-anchor" href="#_2-常见卡顿原因及处方药-💊" aria-label="Permalink to &quot;2. 常见卡顿原因及处方药 💊&quot;">​</a></h2><h3 id="_2-1-频繁与树结构庞大的-setstate" tabindex="-1">2.1 频繁与树结构庞大的 <code>setState</code> <a class="header-anchor" href="#_2-1-频繁与树结构庞大的-setstate" aria-label="Permalink to &quot;2.1 频繁与树结构庞大的 \`setState\`&quot;">​</a></h3><p><strong>病理</strong>： 在巨大的 Widget Tree 顶层调用 <code>setState</code>，会导致整个树及其所有子节点被标记为 dirty，引发地毯式的 <code>build</code> 重建。</p><p><strong>处方</strong>：</p><ul><li><strong>下放状态 (Push State Down)</strong>：只把 <code>setState</code> 写在那个确实需要更新的叶子节点 Widget 里面。</li><li><strong>拆分组件</strong>：如果你发现一个 <code>.dart</code> 文件有 1000 行，把其中的模块抽离成独立的 <code>StatelessWidget</code> / <code>StatefulWidget</code>。</li></ul><h3 id="_2-2-不必要的重绘-repaintboundary" tabindex="-1">2.2 不必要的重绘 (<code>RepaintBoundary</code>) <a class="header-anchor" href="#_2-2-不必要的重绘-repaintboundary" aria-label="Permalink to &quot;2.2 不必要的重绘 (\`RepaintBoundary\`)&quot;">​</a></h3><p><strong>病理</strong>： Flutter 渲染引擎会将一块区域作为 Layer 绘制。如果你在一个列表中有一个一直转圈的 <code>CircularProgressIndicator</code>（不断重绘），它有可能会导致周围的静态文本和图片（甚至整个列表！）陪着它一帧一帧地重绘。这吃光了 GPU。</p><p><strong>处方</strong>： 使用 <code>RepaintBoundary</code> 将高频重绘的区域&quot;圈&quot;起来。</p><div class="language-dart vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">dart</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">RepaintBoundary</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  child</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> CircularProgressIndicator</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(),</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>这样引擎会自动分配一块独立的显存图层给它，不波及周边的静态大哥们。</p><h3 id="_2-3-const-的终极威力" tabindex="-1">2.3 <code>const</code> 的终极威力 <a class="header-anchor" href="#_2-3-const-的终极威力" aria-label="Permalink to &quot;2.3 \`const\` 的终极威力&quot;">​</a></h3><p><strong>病理</strong>： 每次运行 <code>build</code> 时，普通的 Widget 都会在内存中重新实例化，给 GC（垃圾回收器）带来极大压力，导致偶发性卡顿。</p><p><strong>处方</strong>： 只要你的 Widget 完全不依赖任何外部变量（如硬编码的 padding，文字颜色等），<strong>前置加上 <code>const</code></strong>。 在编译期间，Dart 会将 <code>const</code> 组件提取为编译时常量，后续任意次 <code>build</code> 连实例化的过程都省了，直接复用内存对象的引用。</p><blockquote><p>你一定要开启 <code>flutter_lints</code> 里的 <code>prefer_const_constructors</code> 规则，然后让 IDE 帮你自动加上蓝色的修饰线。</p></blockquote><hr><h2 id="_3-riverpod-的极客性能利器-select" tabindex="-1">3. Riverpod 的极客性能利器：<code>select</code> <a class="header-anchor" href="#_3-riverpod-的极客性能利器-select" aria-label="Permalink to &quot;3. Riverpod 的极客性能利器：\`select\`&quot;">​</a></h2><p>前面对付的是原生的 <code>setState</code>，如果你用了 Riverpod，状态树通常是在全局维护的。</p><p>假设你有一个极其巨大的用户对象存储在 State 中：</p><div class="language-dart vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">dart</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">class</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> User</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  final</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> String</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> name;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  final</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> age;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // 还有 100 个字段...</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>如果你只想显示名字，传统做法：</p><div class="language-dart vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">dart</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">final</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> user </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ref.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">watch</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(userProvider);</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">return</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Text</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(user.name);</span></span></code></pre></div><p><strong>致命缺陷</strong>：如果这个 <code>user</code> 的 <code>age</code> 改变了，这个只显示名字的 <code>Text</code> 所在层级<strong>也会被强制触发重建（rebuild）</strong>，造成性能极大的浪费！</p><p><strong>终极解法：使用 <code>.select</code></strong></p><div class="language-dart vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">dart</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">final</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> userName </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ref.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">watch</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(userProvider.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">select</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">((user) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> user.name));</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">return</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Text</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(userName);</span></span></code></pre></div><p><strong>此时，只有当 <code>user.name</code> 发生真实字符串哈希变化时，这个 Widget 才会重绘！完美！</strong></p><hr><h2 id="_4-tree-shaking-包体积分析-app-size" tabindex="-1">4. Tree Shaking + 包体积分析 (App Size) <a class="header-anchor" href="#_4-tree-shaking-包体积分析-app-size" aria-label="Permalink to &quot;4. Tree Shaking + 包体积分析 (App Size)&quot;">​</a></h2><p>性能不仅仅是流畅度，还包含：占多大内存、你的包有多少 MB、下载要多久。</p><p>对于 Web 前端，你会看 Webpack Bundle Analyzer。 在 Flutter，由于自带 AOT (Ahead Of Time) 提前编译模式，本身自带强大的摇树优化 (Tree Shaking)（没用到的类和函数在构建时直接删掉）。</p><p>如果你觉得打出来的包大，运行下面命令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">flutter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apk</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --analyze-size</span></span></code></pre></div><p>或对于 iOS：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">flutter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ipa</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --analyze-size</span></span></code></pre></div><p>它会在当前目录生成一个 JSON 报告，然后在终端告诉你：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✓ Built build/app/outputs/flutter-apk/app-release.apk (16.2MB).</span></span>
<span class="line"><span>├── libapp.so (7.4MB)</span></span>
<span class="line"><span>├── assets (2.1MB)</span></span>
<span class="line"><span>└── res (1.5MB)</span></span></code></pre></div><p>你可以清楚地看到是你的图片（<code>assets</code>）放得太多，还是你用的某个地图 SDK（常常几 MB）导致了体积膨胀。</p><hr><h2 id="_5-动手体验-性能测试-demo" tabindex="-1">5. 动手体验：性能测试 Demo <a class="header-anchor" href="#_5-动手体验-性能测试-demo" aria-label="Permalink to &quot;5. 动手体验：性能测试 Demo&quot;">​</a></h2><p>我们利用 Day28 产出的 <code>performance_demo_page.dart</code> 带你体会一下。</p><p>里面写了一个对比：</p><ul><li>左边/或者某个选项是用未经优化的组件，它在列表滚动的时候会引发整页重绘。</li><li>右边/或者开启优化后加上了 <code>RepaintBoundary</code> 定位了重绘范围，你可以打开 Android Studio 或 VS Code 左边的 <code>Flutter Performance</code> 面板，勾选 <strong>&quot;Highlight Repaints&quot; (高亮重绘区域)</strong>。</li><li>这时候你能非常直观地看见：未优化的组件周边疯狂闪烁变色，而优化的组件安静如常，只有需要更新的地方才有闪烁色块！</li></ul><blockquote><p>📌 <strong>性能优化箴言</strong>：不要过早优化（Premature optimization is the root of all evil），先保证功能正确；然后在感觉到卡顿时，<strong>一定要用 DevTools 找到量化数据而不是瞎猜</strong>，再对症下药！</p></blockquote>`,57)])])}const g=e(n,[["render",o]]);export{k as __pageData,g as default};
